record_types.code:
type gsl_movstat_accum is record
   size : access function
     (arg1 : size_t) return size_t;
   init : access function
     (arg1 : size_t; arg2 : System.Address)
      return int;
   insert : access function
     (arg1 : double; arg2 : System.Address)
      return int;
   delete_oldest : access function
     (arg1 : System.Address)
      return int;
   get : access function
     (arg1 : System.Address; arg2 : access double; arg3 : System.Address)
      return int;
end record;

type gsl_movstat_function is record
   c_function : access function
     (arg1 : size_t; arg2 : in out double_array; arg3 : System.Address)
      return double;
   params : System.Address;
end record;

type gsl_movstat_workspace is record
   H          : aliased size_t;
   J          : aliased size_t;
   K          : aliased size_t;
   work       : access double;
   state      : System.Address;
   state_size : aliased size_t;
end record;

